SET NAMES utf8mb4;
SET time_zone = '+07:00';
SET SQL_MODE = 'NO_AUTO_VALUE_ON_ZERO';
SET FOREIGN_KEY_CHECKS = 0;

CREATE DATABASE IF NOT EXISTS `elearning_db` CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE `elearning_db`;

DROP TABLE IF EXISTS `cart_items`;
CREATE TABLE `cart_items` (
  `id` int NOT NULL AUTO_INCREMENT,
  `cart_id` int NOT NULL,
  `course_id` int NOT NULL,
  `price` decimal(10,2) NOT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `cart_id` (`cart_id`,`course_id`),
  KEY `course_id` (`course_id`),
  CONSTRAINT `cart_items_ibfk_1` FOREIGN KEY (`cart_id`) REFERENCES `carts` (`id`) ON DELETE CASCADE,
  CONSTRAINT `cart_items_ibfk_2` FOREIGN KEY (`course_id`) REFERENCES `courses` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=23 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `carts`;
CREATE TABLE `carts` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL,
  `total_price` decimal(10,2) DEFAULT '0.00',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `user_id` (`user_id`),
  CONSTRAINT `carts_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO `carts` (`id`, `user_id`, `total_price`, `created_at`, `updated_at`) VALUES
('1', '3', '0.00', '2026-05-31 15:28:05', '2026-06-20 01:21:36');

DROP TABLE IF EXISTS `courses`;
CREATE TABLE `courses` (
  `id` int NOT NULL AUTO_INCREMENT,
  `title` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL,
  `slug` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `thumbnail` text COLLATE utf8mb4_unicode_ci,
  `price` decimal(10,2) NOT NULL,
  `discount_price` decimal(10,2) DEFAULT NULL,
  `level` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `category` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `instructor` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `duration` int DEFAULT NULL,
  `total_lectures` int DEFAULT NULL,
  `published` tinyint(1) DEFAULT '0',
  `enrollment_count` int DEFAULT '0',
  `rating` double DEFAULT '0',
  `rating_count` int DEFAULT '0',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `slug` (`slug`)
) ENGINE=InnoDB AUTO_INCREMENT=24 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO `courses` (`id`, `title`, `slug`, `description`, `thumbnail`, `price`, `discount_price`, `level`, `category`, `instructor`, `duration`, `total_lectures`, `published`, `enrollment_count`, `rating`, `rating_count`, `created_at`, `updated_at`) VALUES
('1', 'Lập trình Web toàn diện với HTML, CSS và JavaScript', 'lap-trinh-web-toan-dien-voi-html-css-va-javascript', 'Khóa học này sẽ đưa bạn từ con số 0 trở thành một nhà phát triển Front-End thực thụ. Bạn sẽ học cách xây dựng các giao diện web tuyệt đẹp, tương tác mạnh mẽ và tương thích mọi thiết bị di động.', 'data:image/png;base64,', '129000.00', '99000.00', 'BEGINNER', 'Web Development', 'Khánh Nguyễn', '1200', '15', '1', '1', '4.8', '32', '2026-05-31 15:00:17', '2026-06-19 19:57:20'),
('2', 'Lập trình PHP & MySQL từ cơ bản đến nâng cao', 'lap-trinh-php-mysql-tu-co-ban-den-nang-cao', 'Làm chủ ngôn ngữ lập trình Back-End phổ biến nhất thế giới. Tự tay thiết kế và vận hành hệ thống Cơ sở dữ liệu MySQL bảo mật cao, xây dựng dự án website bán hàng thực tế.', 'data:image/png;base64,', '120000.00', '100000.00', 'INTERMEDIATE', 'Web Development', 'Hoàng Lâm', '1500', '18', '1', '1', '4.7', '24', '2026-05-31 15:00:17', '2026-06-19 14:25:39'),
('3', 'Làm chủ ReactJS và Spring Boot trong 30 ngày', 'lam-chu-reactjs-va-spring-boot-trong-30-ngay', 'Khóa học Full-Stack cao cấp kết hợp thư viện UI hàng đầu ReactJS cùng với Framework backend Spring Boot của Java. Phù hợp cho những ai muốn thăng tiến thu nhập lên ngàn đô.', 'data:image/png;base64,', '250000.00', '200000.00', 'ADVANCED', 'Web Development', 'Tùng Sơn', '2100', '25', '1', '0', '4.9', '15', '2026-05-31 15:00:17', '2026-06-19 19:56:46'),
('4', 'JavaScript hiện đại từ cơ bản đến chuyên sâu', 'javascript-hien-dai-tu-co-ban-den-chuyen-sau', 'Làm chủ JavaScript ES6+, DOM, bất đồng bộ và kỹ thuật xây dựng ứng dụng web tương tác.', 'https://images.viblo.asia/dfafaa32-e13c-4b50-ae37-58742c1727dd.png', '149000.00', '119000.00', 'BEGINNER', 'Web Development', 'Minh Anh', '1080', '18', '1', '0', '4.8', '41', '2026-06-19 18:58:00', '2026-06-19 19:56:17'),
('5', 'ReactJS thực chiến: Xây dựng ứng dụng thương mại điện tử', 'reactjs-thuc-chien-xay-dung-ung-dung-thuong-mai-dien-tu', 'Xây dựng ứng dụng React hoàn chỉnh với Router, Hooks, quản lý trạng thái và tích hợp API.', 'https://images.viblo.asia/da4b60f5-c0e3-4872-aec0-90fbe4ca0a61.png', '259000.00', '199000.00', 'INTERMEDIATE', 'Frontend Development', 'Hoàng Nam', '1320', '22', '1', '0', '4.9', '36', '2026-06-19 18:58:00', '2026-06-19 19:55:49'),
('6', 'Vue.js 3 và Pinia cho người mới bắt đầu', 'vue-js-3-va-pinia-cho-nguoi-moi-bat-dau', 'Tiếp cận Vue 3, Composition API và Pinia qua dự án quản lý công việc thực tế.', 'https://blog.haposoft.com/content/images/2021/12/Logo-Vuejs.png', '179000.00', '139000.00', 'BEGINNER', 'Frontend Development', 'Thu Trang', '900', '16', '1', '0', '4.7', '28', '2026-06-19 18:58:00', '2026-06-19 19:55:20'),
('7', 'Node.js và Express: Phát triển REST API', 'node-js-va-express-phat-trien-rest-api', 'Thiết kế REST API bảo mật với Node.js, Express, JWT và cơ sở dữ liệu thực tế.', 'https://images.viblo.asia/28538475-4b47-4933-bb6f-c362a620d252.png', '239000.00', '189000.00', 'INTERMEDIATE', 'Backend Development', 'Quang Huy', '1260', '20', '1', '0', '4.8', '33', '2026-06-19 18:58:00', '2026-06-19 19:54:45'),
('8', 'Laravel 11: Xây dựng website bán hàng', 'laravel-11-xay-dung-website-ban-hang', 'Học Laravel qua dự án bán hàng với phân quyền, giỏ hàng, đơn hàng và thanh toán.', 'data:image/png;base64,', '279000.00', '219000.00', 'INTERMEDIATE', 'Backend Development', 'Đức Thịnh', '1500', '25', '1', '0', '4.9', '45', '2026-06-19 18:58:00', '2026-06-19 19:53:34'),
('9', 'Python Django toàn tập', 'python-django-toan-tap', 'Xây dựng website bằng Django, ORM, xác thực người dùng và triển khai ứng dụng.', 'https://static.vietnix.vn/wp-content/uploads/2024/07/django.webp', '269000.00', '209000.00', 'INTERMEDIATE', 'Backend Development', 'Ngọc Linh', '1440', '24', '1', '0', '4.8', '31', '2026-06-19 18:58:00', '2026-06-19 19:54:10'),
('10', 'Java Spring Boot và Microservices', 'java-spring-boot-va-microservices', 'Phát triển hệ thống backend hiện đại với Spring Boot, JPA, Security và Microservices.', 'data:image/png;base64,', '329000.00', '269000.00', 'ADVANCED', 'Backend Development', 'Tuấn Kiệt', '1800', '30', '1', '0', '4.9', '39', '2026-06-19 18:58:00', '2026-06-19 19:53:07'),
('11', 'ASP.NET Core MVC thực hành', 'asp-net-core-mvc-thuc-hanh', 'Xây dựng ứng dụng quản lý với C#, ASP.NET Core MVC, Entity Framework và SQL Server.', 'data:image/jpeg;base64,', '289000.00', '229000.00', 'INTERMEDIATE', 'Backend Development', 'Bảo Long', '1560', '26', '1', '0', '4.7', '22', '2026-06-19 18:58:00', '2026-06-19 19:52:35'),
('12', 'Flutter: Lập trình ứng dụng đa nền tảng', 'flutter-lap-trinh-ung-dung-da-nen-tang', 'Tạo ứng dụng Android và iOS với Flutter, Dart, Firebase và kiến trúc ứng dụng.', 'data:image/png;base64,', '299000.00', '239000.00', 'INTERMEDIATE', 'Mobile Development', 'Phương Vy', '1620', '27', '1', '0', '4.8', '34', '2026-06-19 18:58:00', '2026-06-19 19:52:04'),
('13', 'React Native từ cơ bản đến thực chiến', 'react-native-tu-co-ban-den-thuc-chien', 'Phát triển ứng dụng di động bằng React Native, điều hướng, API và lưu trữ dữ liệu.', 'data:image/png;base64,', '279000.00', '219000.00', 'INTERMEDIATE', 'Mobile Development', 'Gia Hân', '1380', '23', '1', '0', '4.7', '25', '2026-06-19 18:58:00', '2026-06-19 19:48:41'),
('14', 'SQL và thiết kế cơ sở dữ liệu', 'sql-va-thiet-ke-co-so-du-lieu', 'Nắm vững truy vấn SQL, chuẩn hóa dữ liệu, chỉ mục và tối ưu hiệu năng cơ sở dữ liệu.', 'https://lh5.googleusercontent.com/proxy/zfkM3q_6N46FVhP9rX9r8kVNe5IzPjSOtFb8zQBRBLYcdnctS26MbiuoSBkndrkThPvChJEKSHyzvWsuOFDWi8gtz8PefQm9zOY', '169000.00', '129000.00', 'BEGINNER', 'Database', 'Thanh Tùng', '960', '16', '1', '0', '4.8', '48', '2026-06-19 18:58:00', '2026-06-19 19:48:13'),
('15', 'Git, GitHub và quy trình làm việc nhóm', 'git-github-va-quy-trinh-lam-viec-nhom', 'Sử dụng Git thành thạo, quản lý nhánh, xử lý xung đột và cộng tác qua GitHub.', 'data:image/png;base64,', '99000.00', '79000.00', 'BEGINNER', 'DevOps', 'Khánh An', '600', '10', '1', '0', '4.9', '52', '2026-06-19 18:58:00', '2026-06-19 19:47:01'),
('16', 'Docker và Kubernetes cho Developer', 'docker-va-kubernetes-cho-developer', 'Đóng gói, triển khai và vận hành ứng dụng với Docker, Compose và Kubernetes.', 'data:image/png;base64,', '319000.00', '259000.00', 'ADVANCED', 'DevOps', 'Việt Dũng', '1680', '28', '1', '0', '4.8', '30', '2026-06-19 18:58:00', '2026-06-19 19:41:36'),
('17', 'Triển khai ứng dụng trên AWS', 'trien-khai-ung-dung-tren-aws', 'Làm quen EC2, S3, RDS, IAM và quy trình triển khai ứng dụng web trên AWS.', 'https://inda.vn/wp-content/uploads/2023/08/dich-vu-AWS-3.jpg', '299000.00', '249000.00', 'ADVANCED', 'Cloud Computing', 'Hải Đăng', '1440', '24', '1', '0', '4.7', '21', '2026-06-19 18:58:00', '2026-06-19 19:46:35'),
('18', 'UI UX Design dành cho lập trình viên', 'ui-ux-design-danh-cho-lap-trinh-vien', 'Hiểu nguyên lý thiết kế giao diện, hệ thống màu sắc, typography và trải nghiệm người dùng.', 'https://www.toponseek.com/wp-content/uploads/2024/07/Whats-the-Difference-Between-UX-Design-vs.-UI-Design_@3x-1-scaled-1.jpg', '189000.00', '149000.00', 'BEGINNER', 'UI/UX Design', 'Mai Chi', '840', '14', '1', '0', '4.8', '37', '2026-06-19 18:58:00', '2026-06-19 19:49:16'),
('19', 'TypeScript chuyên sâu cho dự án lớn', 'typescript-chuyen-sau-cho-du-an-lon', 'Ứng dụng TypeScript, Generics, Utility Types và kiến trúc mã nguồn dễ bảo trì.', 'data:image/png;base64,', '229000.00', '179000.00', 'ADVANCED', 'Frontend Development', 'Đình Phúc', '1200', '20', '1', '0', '4.9', '29', '2026-06-19 18:58:00', '2026-06-19 19:50:34'),
('20', 'Cấu trúc dữ liệu và giải thuật với JavaScript', 'cau-truc-du-lieu-va-giai-thuat-voi-javascript', 'Rèn luyện tư duy giải thuật qua mảng, danh sách liên kết, cây, đồ thị và bài toán thực tế.', 'https://s3-hfx03.fptcloud.com/codelearnstorage/files/thumbnails/cau-truc-du-lieu-va-giai-thuat_ef33392c074c4cd29a9892f11abbc2bc.png', '249000.00', '199000.00', 'INTERMEDIATE', 'Computer Science', 'Nhật Minh', '1500', '25', '1', '0', '4.8', '43', '2026-06-19 18:58:00', '2026-06-19 19:43:13'),
('21', 'Bảo mật ứng dụng Web căn bản', 'bao-mat-ung-dung-web-can-ban', 'Nhận biết và phòng chống SQL Injection, XSS, CSRF cùng các lỗ hổng web phổ biến.', 'https://static.vncdn.vn/vnetwork.vn/pub/websites/uploads/1/35/bao-mat-website-la-gi.jpg', '269000.00', '219000.00', 'INTERMEDIATE', 'Cyber Security', 'Trọng Nghĩa', '1260', '21', '1', '0', '4.9', '27', '2026-06-19 18:58:00', '2026-06-19 19:49:57'),
('22', 'Thiết kế RESTful API chuyên nghiệp', 'thiet-ke-restful-api-chuyen-nghiep', 'Thiết kế API nhất quán, xác thực, phân trang, xử lý lỗi và viết tài liệu OpenAPI.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSPsj-fi1IfUFzDzaagqsTi69bDJf55hlFiFA&s', '219000.00', '169000.00', 'INTERMEDIATE', 'Backend Development', 'Anh Khoa', '1080', '18', '1', '0', '4.7', '24', '2026-06-19 18:58:00', '2026-06-19 19:44:12'),
('23', 'Kiểm thử Web với PHPUnit và Playwright', 'kiem-thu-web-voi-phpunit-va-playwright', 'Xây dựng unit test, integration test và kiểm thử giao diện tự động cho ứng dụng web.', 'https://academy.betterbytesvn.com/wp-content/uploads/2025/04/playwright-logo.png', '259000.00', '209000.00', 'ADVANCED', 'Software Testing', 'Yến Nhi', '1320', '22', '1', '0', '4.8', '26', '2026-06-19 18:58:00', '2026-06-19 20:02:51');

DROP TABLE IF EXISTS `enrollments`;
CREATE TABLE `enrollments` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL,
  `course_id` int NOT NULL,
  `enrolled_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `progress` double DEFAULT '0',
  `completed_at` timestamp NULL DEFAULT NULL,
  `active` tinyint(1) DEFAULT '1',
  PRIMARY KEY (`id`),
  UNIQUE KEY `user_id` (`user_id`,`course_id`),
  KEY `course_id` (`course_id`),
  CONSTRAINT `enrollments_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `enrollments_ibfk_2` FOREIGN KEY (`course_id`) REFERENCES `courses` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

