DROP TABLE IF EXISTS `lessons`;
CREATE TABLE `lessons` (
  `id` int NOT NULL AUTO_INCREMENT,
  `course_id` int NOT NULL,
  `title` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `video_url` text COLLATE utf8mb4_unicode_ci,
  `duration` int DEFAULT NULL,
  `order_index` int NOT NULL,
  `is_free` tinyint(1) DEFAULT '0',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `course_id` (`course_id`),
  CONSTRAINT `lessons_ibfk_1` FOREIGN KEY (`course_id`) REFERENCES `courses` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=14 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO `lessons` (`id`, `course_id`, `title`, `description`, `video_url`, `duration`, `order_index`, `is_free`, `created_at`, `updated_at`) VALUES
('1', '1', 'Bài 1: Tổng quan về thế giới lập trình Web', 'Chào mừng bạn đến với khóa học. Bài học này sẽ giới thiệu cho bạn định hướng trở thành Web Developer.', 'https://interactive-examples.mdn.mozilla.net/media/cc0-videos/flower.mp4', '15', '1', '1', '2026-05-31 15:00:17', '2026-06-20 00:25:05'),
('2', '1', 'Bài 2: HTML5 là gì? Các thẻ cơ bản cần biết', 'Hướng dẫn chi tiết cách tạo trang HTML đầu tiên và cách sử dụng các thẻ div, p, headings, a, img.', 'https://interactive-examples.mdn.mozilla.net/media/cc0-videos/flower.mp4', '25', '2', '0', '2026-05-31 15:00:17', '2026-06-20 00:25:05'),
('3', '1', 'Bài 3: Tạo kiểu cho trang web bằng CSS3', 'Học cách đổi màu sắc, điều chỉnh font chữ, kích thước, khoảng cách margin và padding trong CSS.', 'https://interactive-examples.mdn.mozilla.net/media/cc0-videos/flower.mp4', '35', '3', '0', '2026-05-31 15:00:17', '2026-06-20 00:25:05'),
('4', '1', 'Bài 4: Bố cục Layout nâng cao với Flexbox', 'Sử dụng Flexbox để dàn trang responsive một cách dễ dàng và nhanh chóng.', 'https://interactive-examples.mdn.mozilla.net/media/cc0-videos/flower.mp4', '40', '4', '0', '2026-05-31 15:00:17', '2026-06-20 00:25:05'),
('5', '2', 'Bài 1: Giới thiệu về PHP và XAMPP', 'Cách cài đặt XAMPP để chạy localhost phục vụ cho việc học và lập trình PHP trên máy tính cá nhân.', 'https://interactive-examples.mdn.mozilla.net/media/cc0-videos/flower.mp4', '20', '1', '1', '2026-05-31 15:00:17', '2026-06-20 00:25:05'),
('6', '2', 'Bài 2: Cú pháp PHP cơ bản và Kiểu dữ liệu', 'Làm quen với biến, hằng, câu điều kiện if-else, vòng lặp for và while trong PHP.', 'https://interactive-examples.mdn.mozilla.net/media/cc0-videos/flower.mp4', '30', '2', '0', '2026-05-31 15:00:17', '2026-06-20 00:25:05'),
('7', '2', 'Bài 3: Kết nối cơ sở dữ liệu MySQL bằng PDO', 'Cách kết nối an toàn bảo mật, chống SQL Injection với PDO của PHP.', 'https://interactive-examples.mdn.mozilla.net/media/cc0-videos/flower.mp4', '45', '3', '0', '2026-05-31 15:00:17', '2026-06-20 00:25:05'),
('8', '3', 'Bài 1: Tại sao lại là ReactJS & Spring Boot?', 'Phân tích kiến trúc Single Page Application (SPA) kết hợp RESTful API.', 'https://interactive-examples.mdn.mozilla.net/media/cc0-videos/flower.mp4', '22', '1', '1', '2026-05-31 15:00:17', '2026-06-20 00:25:05'),
('9', '3', 'Bài 2: Khởi tạo Project Spring Boot đầu tiên', 'Hướng dẫn sử dụng Spring Initializr để tạo một ứng dụng Maven Boot.', 'https://interactive-examples.mdn.mozilla.net/media/cc0-videos/flower.mp4', '35', '2', '0', '2026-05-31 15:00:17', '2026-06-20 00:25:05');

DROP TABLE IF EXISTS `order_items`;
CREATE TABLE `order_items` (
  `id` int NOT NULL AUTO_INCREMENT,
  `order_id` int NOT NULL,
  `course_id` int NOT NULL,
  `course_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `price` decimal(10,2) NOT NULL,
  `original_price` decimal(10,2) NOT NULL,
  PRIMARY KEY (`id`),
  KEY `order_id` (`order_id`),
  KEY `course_id` (`course_id`),
  CONSTRAINT `order_items_ibfk_1` FOREIGN KEY (`order_id`) REFERENCES `orders` (`id`) ON DELETE CASCADE,
  CONSTRAINT `order_items_ibfk_2` FOREIGN KEY (`course_id`) REFERENCES `courses` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=46 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

